  description = "Policy to manage image lifecycle"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowImageCreation"
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = "ec2:CreateImage"
        Resource = "*"
      },
      {
        Sid       = "AllowImageUpdate"
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = "ec2:UpdateImage"
        Resource = "*"
      },
      {
        Sid       = "AllowImageDeletion"
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = "ec2:DeleteImage"
