Infraestrutura como codigo para custom-images - FinServe Digital - disaster-recovery-setup:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "eu-frankfurt-1"
}

resource "oci_core_image" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "custom-images-sandbox-063"

  shape          = "VM.Standard.E4.Flex"

  tags = {
    project     = "FinServe Digital - disaster-recovery-setup"
    environment = "sandbox"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment sandbox"
}

output "resource_id" {
  value = oci_core_image.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "eu-frankfurt-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**Configuracao:**
- Compartment: `sandbox`
- Region: `eu-frankfurt-1`
- Shape: `VM.Standard.E4.Flex`
- OCPUs: `64`
- Storage: `500 GB`

Documentacao: https://docs.oracle.com/en-us/iaas/Content/Compute/Concepts/computeoverview.htm

